import { TickRendererProps } from '@visx/axis';

import { Tooltip } from '../../../../..//overlays/tooltip/Tooltip.js';
import type { TruncationMode } from '../../../../../typography/text-ellipsis/TextEllipsis.js';
import { isSafari } from '../../../utils/is-browser-safari.js';
import { charsFontWidth12pixelsSize400Map } from '../../text-ellipsis/chars-font-width-map.js';
import { truncateString } from '../../text-ellipsis/truncate-string.js';

interface TickLabelProps extends TickRendererProps {
  foreignObjectInlineStyle: Record<string, string | number>;
  foreignObjectContentInlineStyle: Record<string, string | number>;
  isTickRotated?: boolean;
  maxSize: number;
  truncationMode: TruncationMode;
  x: number;
  y: number;
}

export const TickLabel = (props: TickLabelProps) => {
  const {
    foreignObjectInlineStyle,
    foreignObjectContentInlineStyle,
    formattedValue,
    maxSize,
    truncationMode,
    x,
    y,
  } = props;

  if (!formattedValue) {
    return null;
  }

  const truncatedValue = truncateString(
    formattedValue,
    maxSize,
    charsFontWidth12pixelsSize400Map,
    truncationMode,
  );

  const disableTooltip = formattedValue === truncatedValue;

  return (
    <g>
      <foreignObject
        x={x}
        y={y}
        height={foreignObjectInlineStyle.height}
        width={foreignObjectInlineStyle.width}
        style={{ ...foreignObjectInlineStyle }}
      >
        {isSafari() && (
          <div
            style={{ ...foreignObjectContentInlineStyle }}
            title={formattedValue}
          >
            {truncatedValue}
          </div>
        )}
        {!isSafari() && (
          <Tooltip
            disabled={disableTooltip}
            text={formattedValue}
            style={{ display: 'inline-block' }}
          >
            <div
              style={{
                ...foreignObjectContentInlineStyle,
                position: 'relative',
              }}
            >
              {truncatedValue}
            </div>
          </Tooltip>
        )}
      </foreignObject>
    </g>
  );
};
